#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n,k,p,q,dis[N],f[N],fa[N],ans,len;
bool b[N];
vector<int> g[N];

int dfs(int x,int last){
    int res=x;
    fa[x]=last;
    for(int y:g[x])
        if(y!=last){
            dis[y]=dis[x]+1;
            int tmp=dfs(y,x);
            res=(dis[tmp]>dis[res]?tmp:res);
        }
    return res;
}

void dfs(int x){
    for(int y:g[x])
        if(y!=fa[x]){
            dfs(y);
            len=max(len,f[x]+f[y]+(b[y]?-1:1));
            f[x]=max(f[x],f[y]+(b[y]?-1:1));
        }
}

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    p=dfs(1,0);
    memset(dis,0,sizeof(dis));
    q=dfs(p,0);
    ans=2*(n-1)-(dis[q]-1);
    if(k>1){
        for(int i=q;i!=p;i=fa[i])
            b[i]=1;
        dfs(p);
        ans-=len-1;
    }
    printf("%d",ans);
    return 0;
}
